onClick:
{{
  (() => {
    const data = getPurchaseLines.data;
    if (!data || data.length === 0) {
      showAlert("No data available to download", "warning");
      return;
    }

    // 1. Get the column headers
    const headers = Object.keys(data[0]);

    // 2. Map the rows to comma-separated values
    const csvRows = data.map(row => 
      headers.map(header => {
        const value = row[header] === null || row[header] === undefined ? "" : row[header];
        // Escape quotes and wrap in double quotes to handle commas inside text fields
        return `"${String(value).replace(/"/g, '""')}"`;
      }).join(",")
    );

    // 3. Combine headers and rows
    const csvContent = [headers.join(","), ...csvRows].join("\r\n");

    // 4. Trigger download as CSV file
    download(csvContent, "Purchase_Invoice_Lines.csv", "text/csv");
  })()
}}
